class LUPrefix {
    private int maxPrefixLength, nextVideo;
    private boolean[] uploaded;

    public LUPrefix(int n) {
        maxPrefixLength = 0;
        nextVideo = 1;
        uploaded = new boolean[n + 1];
    }

    public void upload(int video) {
        uploaded[video] = true;
        if (video == nextVideo) {
            while (uploaded[nextVideo]) nextVideo++;
        }
    }

    public int longest() {
        return nextVideo - 1;
    }
}
```

